import "../App/App.scss";
import Header from "../Header/Header";
import "bootstrap/dist/css/bootstrap.min.css";

const App = () => {
  return (
    <div className="app">
      <Header />
      <div className="container app__container">
        <div className="row">
          <div className="col-lg-6">
            <div className="app__container__name">
              <div>
                <p>Hi, my name is Emeka Osuji</p>
              </div>

              <div className="horizontal-line"></div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
